import { VexClient } from 'vex-sdk';

const vex = new VexClient({ apiKey: 'your-vex-key' });

async function validatePlan(plan: any, input: string) {
  const verified = await vex.verify({
    input,
    plan: {
      steps: plan.steps,
      plugins: plan.functions.map((f: any) => f.name),
    },
    verifications: ['plan_validity'],
    riskProfile: 'high',
  });

  if (!verified) {
    throw new Error('Invalid execution plan detected');
  }

  return plan;
}

